Here's a modern MSTest approach using `HttpMessageHandler` mocking, async test methods, and cancellation testing:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    [Timeout(5000)] // MSTest v3+ timeout in ms
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("http://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.NotFound));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("http://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_Honors_CancellationToken()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("http://example.com", cts.Token));
    }

    // Minimal testable handler — no mocking library needed
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        public FakeHandler(HttpResponseMessage response) => _response = response;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(_response);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Detail |
|---------|--------|
| `async Task` test methods | MSTest awaits them natively — no `.Result` / `.GetAwaiter()` needed |
| `[Timeout(ms)]` | Fails the test if it hangs; works per-method or at class level |
| `CancellationToken` testing | Pre-cancel a `CancellationTokenSource` to verify propagation |
| `Assert.ThrowsExceptionAsync` | Proper async exception assertion (not `ThrowsException`) |
| `HttpMessageHandler` fake | Avoids network calls without heavy mocking frameworks |

> **MSTest v3+ note:** If using `MSTest.Sdk` or MSTest 3.x packages, you can also apply `[Timeout]` at assembly level via `[assembly: Timeout(10000)]` in a `GlobalUsings.cs` to guard all tests against hangs.
